arguments.command:
Get-ChildItem -Path "$env:USERPROFILE\.openclaw\skills" -Directory | ForEach-Object { 
    $dest = "C:\Users\73911\.openclaw\workspace\agents\pv-engineer\skills\$($_.Name)"
    if (Test-Path $dest) {
        Remove-Item -Path $dest -Recurse -Force
    }
    Copy-Item -Path $_.FullName -Destination $dest -Recurse -Force
    Write-Host "✓ 已安装: $($_.Name)"
}
